create extension if not exists pgcrypto;
create type app_role as enum('admin','manager','employee','professional');
create type transaction_type as enum('income','expense');
create type transaction_status as enum('received','paid','pending','partial','cancelled','overdue');
create table salon_settings(id boolean primary key default true check(id),name text not null default 'Kavelar Feminine Beaty',phone text,email text,logo_url text,updated_at timestamptz default now());insert into salon_settings default values;
create table profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text not null,email text not null,phone text,role app_role not null default 'employee',active boolean not null default true,created_at timestamptz default now(),updated_at timestamptz default now());
create table financial_categories(id uuid primary key default gen_random_uuid(),name text not null,type transaction_type not null,active boolean default true,unique(name,type));
create table suppliers(id uuid primary key default gen_random_uuid(),name text not null,document text,phone text,email text,notes text,active boolean default true);
create table professionals(id uuid primary key default gen_random_uuid(),profile_id uuid references profiles(id),name text not null,phone text,email text,specialty text,employment_type text,default_commission_type text,default_commission_value numeric(12,2) default 0,active boolean default true);
create table customers(id uuid primary key default gen_random_uuid(),name text not null,phone text,email text,birth_date date,notes text,active boolean default true);
create table services(id uuid primary key default gen_random_uuid(),category_id uuid references financial_categories(id),name text not null,description text,duration_minutes int not null default 30,cost numeric(12,2) default 0,price numeric(12,2) default 0,default_commission numeric(7,2) default 0,active boolean default true);
create table products(id uuid primary key default gen_random_uuid(),supplier_id uuid references suppliers(id),name text not null,internal_code text unique,barcode text,cost numeric(12,2) default 0,sale_price numeric(12,2) default 0,stock_quantity numeric(12,3) default 0,minimum_stock numeric(12,3) default 0,unit text default 'un',active boolean default true);
create table payment_methods(id uuid primary key default gen_random_uuid(),name text not null unique,percentage_fee numeric(7,4) default 0,fixed_fee numeric(12,2) default 0,settlement_days int default 0,maximum_installments int default 1,active boolean default true);
create table cash_registers(id uuid primary key default gen_random_uuid(),opened_by uuid not null references profiles(id),closed_by uuid references profiles(id),opened_at timestamptz default now(),closed_at timestamptz,initial_balance numeric(12,2) default 0,expected_balance numeric(12,2) default 0,informed_balance numeric(12,2),difference_amount numeric(12,2),status text default 'open' check(status in('open','closed')),opening_notes text,closing_notes text);create unique index one_open_cash on cash_registers((true)) where status='open';
create table financial_transactions(id uuid primary key default gen_random_uuid(),cash_register_id uuid references cash_registers(id),customer_id uuid references customers(id),professional_id uuid references professionals(id),category_id uuid references financial_categories(id),transaction_type transaction_type not null,origin_type text default 'manual',description text not null,gross_amount numeric(12,2) not null,discount_amount numeric(12,2) default 0,additional_amount numeric(12,2) default 0,net_amount numeric(12,2) generated always as(gross_amount-discount_amount+additional_amount) stored,due_date date,competence_date date default current_date,payment_date date,status transaction_status default 'pending',notes text,created_by uuid references profiles(id),deleted_at timestamptz,created_at timestamptz default now(),updated_at timestamptz default now());
create table commissions(id uuid primary key default gen_random_uuid(),professional_id uuid references professionals(id),transaction_id uuid references financial_transactions(id),service_id uuid references services(id),commission_type text,commission_rate numeric(7,2),base_amount numeric(12,2),commission_amount numeric(12,2),status text default 'pending',paid_at timestamptz);
create table cash_movements(id uuid primary key default gen_random_uuid(),cash_register_id uuid references cash_registers(id),type text not null,description text not null,amount numeric(12,2) not null,payment_method_id uuid references payment_methods(id),transaction_id uuid references financial_transactions(id),created_by uuid references profiles(id),created_at timestamptz default now());
create or replace function my_role() returns app_role language sql stable security definer set search_path=public as $$select role from profiles where id=auth.uid() and active$$;
do $$declare t text;begin foreach t in array array['salon_settings','profiles','financial_categories','suppliers','professionals','customers','services','products','payment_methods','cash_registers','financial_transactions','commissions','cash_movements'] loop execute format('alter table %I enable row level security',t);execute format('create policy read_active on %I for select to authenticated using(my_role() is not null)',t);execute format('create policy insert_active on %I for insert to authenticated with check(my_role() is not null)',t);execute format('create policy update_active on %I for update to authenticated using(my_role() is not null)',t);end loop;end$$;

